#!/usr/bin/env node
/**
 * 📚 docs-bot: generate-sdk-reference.js
 *
 * Generates docs/sdk-reference.md from sdk/ package.json files
 * and existing sdk-registry.json (if available from sdk-bot).
 */

'use strict';

const fs   = require('fs');
const path = require('path');

const ROOT    = path.resolve(__dirname, '..', '..');
const SDK_DIR = path.resolve(ROOT, 'sdk');
const DOCS    = path.resolve(ROOT, 'docs');

fs.mkdirSync(DOCS, { recursive: true });

// Try to load sdk-registry.json generated by sdk-bot
let registry = null;
try {
  registry = JSON.parse(fs.readFileSync(path.join(DOCS, 'sdk-registry.json'), 'utf8'));
} catch {}

// Fall back to scanning sdk/ directly
const sdkDirs = fs.readdirSync(SDK_DIR, { withFileTypes: true })
  .filter(d => d.isDirectory())
  .map(d => d.name)
  .sort();

const sdks = registry?.sdks || sdkDirs.map(slug => {
  const pkgPath = path.join(SDK_DIR, slug, 'package.json');
  let pkg = {};
  try { pkg = JSON.parse(fs.readFileSync(pkgPath, 'utf8')); } catch {}
  return {
    slug,
    name: pkg.name || slug,
    version: pkg.version || '—',
    description: pkg.description || '',
    main: pkg.main || '',
    license: pkg.license || '',
    keywords: pkg.keywords || [],
    dependencies: Object.keys(pkg.dependencies || {}),
  };
});

const timestamp = new Date().toISOString();

const lines = [
  '# 📦 SDK Reference',
  '',
  `**Generated:** ${timestamp}`,
  `**Total SDKs:** ${sdks.length}`,
  `**Bot:** organism-docs-bot 📚`,
  '',
  '## Quick Reference',
  '',
  '| SDK | Version | Description |',
  '|---|---|---|',
  ...sdks.map(s => `| **${s.name}** | \`${s.version}\` | ${s.description || '—'} |`),
  '',
  '## SDK Details',
  '',
  ...sdks.map(s => [
    `### ${s.name}`,
    '',
    `\`\`\``,
    `npm install ${s.name}`,
    `\`\`\``,
    '',
    `- **Package:** \`${s.name}\``,
    `- **Version:** \`${s.version}\``,
    `- **Entry:** \`${s.main}\``,
    `- **License:** ${s.license || '—'}`,
    s.description ? `- **Description:** ${s.description}` : '',
    s.keywords?.length ? `- **Keywords:** ${s.keywords.join(', ')}` : '',
    s.dependencies?.length ? `- **Dependencies:** ${s.dependencies.join(', ')}` : '',
    '',
  ].filter(Boolean).join('\n')),
  '---',
  '',
  '*Generated by organism-docs-bot 📚*',
];

fs.writeFileSync(path.join(DOCS, 'sdk-reference.md'), lines.join('\n'));
console.log(`✅ SDK reference: ${sdks.length} SDKs → docs/sdk-reference.md`);
